import React, { useState } from 'react';

const App = () => {
  const [products, setProducts] = useState([
    { name: 'Product A', price: 10.99 },
    { name: 'Product B', price: 5.99 },
    { name: 'Product C', price: 7.99 }
  ]);
  const [selectedProducts, setSelectedProducts] = useState([]);
  const [filter, setFilter] = useState('');
  const [total, setTotal] = useState(0);

  const handleSelectProduct = (product) => {
    if (selectedProducts.includes(product)) {
      setSelectedProducts(selectedProducts.filter((p) => p !== product));
    } else {
      setSelectedProducts([...selectedProducts, product]);
    }
    calculateTotal();
  };

  const calculateTotal = () => {
    const selectedProductPrices = selectedProducts.map((product) => product.price);
    setTotal(selectedProductPrices.reduce((a, b) => a + b, 0));
  };

  const handleFilterChange = (event) => {
    setFilter(event.target.value);
  };

  return (
    <div className="min-h-screen bg-[#090a0f] text-white p-4 flex items-center justify-center">
      <div className="bg-white p-4 w-1/2">
        <div className="flex justify-between mb-4">
          <input type="search" placeholder="Search" className="p-2 w-1/2" onChange={handleFilterChange} />
          <select className="p-2 w-1/2" value={filter} onChange={handleFilterChange}>
            <option value="">All</option>
            <option value="Product A">Product A</option>
            <option value="Product B">Product B</option>
            <option value="Product C">Product C</option>
          </select>
        </div>
        <table className="w-full border-collapse">
          <thead>
            <tr>
              <th className="text-left p-2">Product Name</th>
              <th className="text-left p-2">Price</th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr key={product.name} className={`bg-${filter === '' ? 'white' : 'gray-200'} hover:bg-gray-200`}> 
                <td className="p-2 text-left">{product.name}</td>
                <td className="p-2 text-left">$ {product.price}</td>
                <td className="p-2 text-left">
                  <input
                    type="checkbox"
                    checked={selectedProducts.includes(product)}
                    onChange={() => handleSelectProduct(product)}
                  />
                </td>
              </tr>
            ))}
          </tbody>
        </table>
        <div className="flex justify-between items-center mb-4 mt-4">
          <h1 className="text-2xl">Total: $ {total}</h1>
          <button className="bg-blue-500 hover:bg-blue-700 text-white font-bold py-2 px-4 rounded">
            Checkout
          </button>
        </div>
      </div>
    </div>
  );
};

export default App;
